539			return opv1.NodeDisruptionPolicyStatusAction{Type: opv1.RebootStatusAction}
540		case opv1.ReloadSpecAction:
541			return opv1.NodeDisruptionPolicyStatusAction{Type: opv1.ReloadStatusAction, Reload: &opv1.ReloadService{
