81	// IsUpdated check whether polcies in this object are synced to status
82	func (ndp NodeDisruptionPolicy) IsUpdated() (bool, error) {
83		latest := NewNodeDisruptionPolicy(ndp.oc)
84		err := json.Unmarshal([]byte(ndp.GetOrFail("{.status.nodeDisruptionPolicyStatus.clusterPolicies}")), &latest)
85		if err != nil {
86			return false, err
87		}
88	
89		updatedPolices := 0
90		for _, file := range ndp.Files {
91			for _, latestFile := range latest.Files {
92				if file.Equals(*latestFile) {
93					updatedPolices++
94				}
95			}
96		}
97	
98		for _, unit := range ndp.Units {
99			for _, latestUnit := range latest.Units {
100				if unit.Equals(*latestUnit) {
101					updatedPolices++
102				}
103			}
104		}
105	
106		if ndp.SSHKey != nil && ndp.SSHKey.Equals(*latest.SSHKey) {
107			updatedPolices++
108		}
109	
110		currentPolicies := len(ndp.Files) + len(ndp.Units)
111		if ndp.SSHKey != nil {
112			currentPolicies++
113		}
114	
115		return updatedPolices == currentPolicies, nil
116	
117	}
