662				klog.Infof("NodeDisruptionPolicy %v found for diff file %s", actionsFound, diffPath)
663				actions = append(actions, actionsFound...)
664			} else {
665				// If this file path has no policy defined, default to reboot
666				klog.V(4).Infof("no policy found for diff path %s", diffPath)
667				return []opv1.NodeDisruptionPolicyStatusAction{{
668					Type: opv1.RebootStatusAction,
669				}}
670			}
671		}
672	
673		// Step through all unit based policies, and build out the actions object
674		for _, diffUnit := range diffUnitSet {
675			unitFound := false
676			for _, policyUnit := range clusterPolicies.Units {
677				klog.V(4).Infof("comparing policy unit name %s to diff unit name %s", string(policyUnit.Name), diffUnit)
678				if string(policyUnit.Name) == diffUnit {
679					klog.Infof("NodeDisruptionPolicy %v found for diff unit %s!", policyUnit.Actions, diffUnit)
680					actions = append(actions, policyUnit.Actions...)
681					unitFound = true
682					break
683				}
684			}
685			if !unitFound {
686				// If this unit has no policy defined, default to reboot
687				klog.V(4).Infof("no policy found for diff unit %s", diffUnit)
688				return []opv1.NodeDisruptionPolicyStatusAction{{
689					Type: opv1.RebootStatusAction,
690				}}
691			}
692		}
693	
694		// SSH only has one possible policy(and there is a default), so blindly add that if there is an SSH diff
695		if diffSSH {
696			klog.Infof("SSH diff detected, applying SSH policy %v", clusterPolicies.SSHKey.Actions)
697			actions = append(actions, clusterPolicies.SSHKey.Actions...)
698		}
699	
700		// If any of the actions need a reboot, then just return a single Reboot action
701		if apihelpers.CheckNodeDisruptionActionsForTargetActions(actions, opv1.RebootStatusAction) {
702			return []opv1.NodeDisruptionPolicyStatusAction{{
703				Type: opv1.RebootStatusAction,
704			}}
705		}
706	
707		// If there is a "None" action in conjunction with other kinds of actions, strip out the "None" action elements as it is redundant
708		if apihelpers.CheckNodeDisruptionActionsForTargetActions(actions, opv1.NoneStatusAction) {
709			if apihelpers.CheckNodeDisruptionActionsForTargetActions(actions, opv1.DrainStatusAction, opv1.ReloadStatusAction, opv1.RestartStatusAction, opv1.DaemonReloadStatusAction, opv1.SpecialStatusAction) {
710				finalActions := []opv1.NodeDisruptionPolicyStatusAction{}
711				for _, action := range actions {
712					if action.Type != opv1.NoneStatusAction {
713						finalActions = append(finalActions, action)
714					}
715				}
716				return finalActions
717			}
718			// If we're here, this means that the action list has only "None" actions; return a single "None" Action
719			return []opv1.NodeDisruptionPolicyStatusAction{{
720				Type: opv1.NoneStatusAction,
721			}}
722		}
723	
724		// If we're here, return as is - this means action list had zero "None" actions in the list
725		return actions
726	}
