130	// isDrainRequiredForNodeDisruptionActions determines whether node drain is required or not to apply config changes for this set of NodeDisruptionActions
131	func isDrainRequiredForNodeDisruptionActions(actions []opv1.NodeDisruptionPolicyStatusAction, oldIgnConfig, newIgnConfig ign3types.Config) (bool, error) {
132		klog.Infof("Checking drain required for node disruption actions")
133		if apihelpers.CheckNodeDisruptionActionsForTargetActions(actions, opv1.RebootStatusAction, opv1.DrainStatusAction) {
134			// We definitely want to perform drain for these cases
135			return true, nil
136		} else if apihelpers.CheckNodeDisruptionActionsForTargetActions(actions, opv1.SpecialStatusAction) {
137			// This is a specially reserved action for "/etc/containers/registries.conf" and for this action, drain may or may not be necessary
138			isSafe, err := isSafeContainerRegistryConfChanges(oldIgnConfig, newIgnConfig)
139			if err != nil {
140				return false, err
141			}
142			return !isSafe, nil
143		}
144		// If only other actions are being done, no drain is necessary
145		return false, nil
146	}
