148	// isDrainRequired determines whether node drain is required or not to apply config changes.
149	func isDrainRequired(actions, diffFileSet []string, oldIgnConfig, newIgnConfig ign3types.Config) (bool, error) {
150		switch {
151		case ctrlcommon.InSlice(postConfigChangeActionReboot, actions):
152			// Node is going to reboot, we definitely want to perform drain
153			return true, nil
154		case ctrlcommon.InSlice(postConfigChangeActionReloadCrio, actions), ctrlcommon.InSlice(postConfigChangeActionRestartCrio, actions):
155			// Drain may or may not be necessary in case of container registry config changes.
156			if ctrlcommon.InSlice(constants.ContainerRegistryConfPath, diffFileSet) {
157				isSafe, err := isSafeContainerRegistryConfChanges(oldIgnConfig, newIgnConfig)
158				if err != nil {
159					return false, err
160				}
161				return !isSafe, nil
162			}
163			return false, nil
164		case ctrlcommon.InSlice(postConfigChangeActionNone, actions):
165			return false, nil
166		default:
167			// For any unhandled cases, default to drain
168			return true, nil
169		}
170	}
